import { adaptViemWallet } from '@relayprotocol/relay-sdk';

import { relayClient } from './client';
import type { AdaptSolanaKitWalletParams } from './relay-svm-wallet-adapter';
import { adaptSolanaKitWallet } from './relay-svm-wallet-adapter';

import type { WalletClient } from 'viem';
import type { Execute } from '@relayprotocol/relay-sdk';

export const executeQuote = async (quote: Execute, account: WalletClient) => {
  return await relayClient.actions.execute({
    wallet: adaptViemWallet(account),
    quote,
  });
};

export interface ExecuteSolanaParams extends AdaptSolanaKitWalletParams {
  quote: Execute;
}

export const executeSolana = async ({
  quote,
  ...rest
}: ExecuteSolanaParams) => {
  return await relayClient.actions.execute({
    wallet: adaptSolanaKitWallet(rest),
    quote,
  });
};
