import z from 'zod';

import { createWalletClient, http } from 'viem';

import { EVM_CONFIGS, Network, networkSchema } from '@agentcash/networks';

import { toTypedNetworkAddress } from '@/shared/network';
import { TOOL_PARAMS } from '@/shared/descriptions';
import {
  safeExecuteQuote,
  safeExecuteSolana,
  safeGetBridgeDepositQuote,
} from '@/shared/neverthrow/bridge';
import { safeFetchJson } from '@/shared/neverthrow/fetch';
import { getBaseUrl } from '@/shared/utils';

import type { Wallets } from '@/wallet';
import type { Execute } from '@agentcash/bridge';
import type { GlobalFlags } from '@/types';

export const bridgeSchema = z
  .object({
    from: networkSchema.describe(TOOL_PARAMS.bridge.from),
    to: networkSchema.describe(TOOL_PARAMS.bridge.to),
    amount: z.number().positive().describe(TOOL_PARAMS.bridge.amount),
  })
  .refine(({ from, to }) => from !== to, {
    message: 'From and to networks cannot be the same',
  });

export type BridgeInput = z.input<typeof bridgeSchema>;

export const bridge = async (
  args: GlobalFlags<z.infer<typeof bridgeSchema>>,
  wallets: Wallets
) => {
  const { from, to, amount } = args;

  if (from === Network.SOLANA) {
    const request = new Request(`${getBaseUrl(args.dev)}/api/bridge/solana`, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        fromAddress: wallets.svm.address,
        to: toTypedNetworkAddress(to, wallets),
        amount,
      }),
    });
    const response = await safeFetchJson(
      'bridge',
      request,
      z.object({
        success: z.literal(true),
        partiallySignedTransaction: z.string(),
        quote: z.custom<Execute>(),
      })
    );

    if (response.isErr()) {
      return response;
    }

    const { partiallySignedTransaction, quote } = response.value;

    const executeResult = await safeExecuteSolana('bridge', {
      quote,
      signer: wallets.svm,
      partiallySignedTransaction,
    });

    return executeResult.map(
      result => result.data.details ?? { success: true }
    );
  } else {
    const quote = await safeGetBridgeDepositQuote('bridge', {
      from: toTypedNetworkAddress(from, wallets),
      to: toTypedNetworkAddress(to, wallets),
      amount,
    });

    if (quote.isErr()) {
      return quote;
    }

    const executeResult = await safeExecuteQuote(
      'bridge',
      quote.value,
      createWalletClient({
        account: wallets.evm,
        chain: EVM_CONFIGS[from].chain,
        transport: http(
          from === Network.TEMPO
            ? 'https://eng:acard-melody-fashion-finish@rpc.mainnet.tempo.xyz'
            : undefined
        ),
      })
    );

    return executeResult.map(
      result => result.data.details ?? { success: true }
    );
  }
};
