export const relayChainId = (network: Network) => {
  switch (network) {
    case Network.BASE:
    case Network.TEMPO:
      return chainId(network);
    case Network.SOLANA:
      return SOLANA_RELAY_CHAIN.id;
  }
};

export const relayClient = createClient({
  baseApiUrl: MAINNET_RELAY_API,
  source: 'https://agentcash.dev',
  chains: [
    ...Object.values(EVM_CONFIGS).map(config =>
      convertViemChainToRelayChain(config.chain)
    ),
    SOLANA_RELAY_CHAIN,
  ],
});
