import { Network } from '@agentcash/networks';

import type { TypedNetworkAddress } from '@agentcash/networks';
import type { Wallets } from '@/wallet';

export const toTypedNetworkAddress = (
  network: Network,
  wallets: Wallets
): TypedNetworkAddress => {
  if (network === Network.SOLANA) {
    return {
      address: wallets.svm.address,
      network: Network.SOLANA,
    };
  }
  return {
    address: wallets.evm.address,
    network: network,
  };
};
